// Validate payload (structure, ts, values)
if (!msg.payload || typeof msg.payload !== 'object' || Array.isArray(msg.payload) || Object.keys(msg.payload).length === 0) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'body not valid JSON object' };
    return [null, msg];
}

const ts = msg.payload.ts;
const values = msg.payload.values;
if (typeof ts !== 'number' || !Number.isFinite(ts)) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'ts missing or not finite number' };
    return [null, msg];
}

const now = Date.now();
if (ts < now - 30*24*3600*1000 || ts > now + 5*60*1000) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'ts outside acceptable window (now-30d .. now+5min)' };
    return [null, msg];
}

if (typeof values !== 'object' || values === null || Array.isArray(values) || Object.keys(values).length === 0) {
    msg.statusCode = 400;
    msg.payload = { status: 'error', reason: 'values must be non-empty object' };
    return [null, msg];
}

const validValues = {};
for (const [tag, value] of Object.entries(values)) {
    if (value === null || value === undefined) continue;
    validValues[tag] = value;
}

const fs = global.get('fs');
const runtimeConfigPath = env.get('NR_RUNTIME_CONFIG_PATH') || '/data/runtime_config.json';

function loadRuntimeConfig() {
    const cached = flow.get('runtimeConfigCache') || { raw: null, config: {} };
    if (!fs) {
        return { config: cached.config || {}, changed: false };
    }
    try {
        const raw = fs.readFileSync(runtimeConfigPath, 'utf8');
        if (raw !== cached.raw) {
            let parsed;
            try {
                parsed = JSON.parse(raw);
            } catch (err) {
                node.warn('runtime_config parse error: ' + err.message);
                return { config: cached.config || {}, changed: false };
            }
            const cfg = {};
            if (Array.isArray(parsed.expected_tags)) {
                cfg.expected_tags = parsed.expected_tags.filter(t => typeof t === 'string');
            }
            if (typeof parsed.ai_inference_url === 'string' && parsed.ai_inference_url.trim().length > 0) {
                cfg.ai_inference_url = parsed.ai_inference_url.trim();
            }
            if (typeof parsed.inference_emit_interval_ms === 'number' && Number.isFinite(parsed.inference_emit_interval_ms) && parsed.inference_emit_interval_ms > 0) {
                cfg.inference_emit_interval_ms = parsed.inference_emit_interval_ms;
            }
            if (typeof parsed.max_tag_staleness_ms === 'number' && Number.isFinite(parsed.max_tag_staleness_ms) && parsed.max_tag_staleness_ms > 0) {
                cfg.max_tag_staleness_ms = parsed.max_tag_staleness_ms;
            }
            if (typeof parsed.warmup_timeout_ms === 'number' && Number.isFinite(parsed.warmup_timeout_ms) && parsed.warmup_timeout_ms > 0) {
                cfg.warmup_timeout_ms = parsed.warmup_timeout_ms;
            }
            flow.set('runtimeConfigCache', { raw: raw, config: cfg });
            return { config: cfg, changed: true };
        }
        return { config: cached.config || {}, changed: false };
    } catch (_err) {
        if (cached.raw !== null) {
            flow.set('runtimeConfigCache', { raw: null, config: {} });
            return { config: {}, changed: true };
        }
        return { config: {}, changed: false };
    }
}

const runtimeLoad = loadRuntimeConfig();
const expectedTags = runtimeLoad.config.expected_tags;

// Reset lastSeen only if expected_tags signature actually CHANGED (not merely
// on first-load-after-restart where prevSig is empty because memory store was
// cleared but lastSeen is file-persisted). Adding new unrelated config keys
// must not force a warmup cycle either.
if (runtimeLoad.changed) {
    const prevSig = flow.get('prevExpectedTagsSig');  // undefined after fresh boot
    const newSig = (expectedTags || []).slice().sort().join(',');
    if (prevSig !== undefined && prevSig !== newSig) {
        flow.set('lastSeen', {}, 'file');
        flow.set('warmupTimeoutWarned', false);
    }
    flow.set('prevExpectedTagsSig', newSig);
}

// Update LOCF state in persisted store
let lastSeen = flow.get('lastSeen', 'file') || {};
for (const [tag, value] of Object.entries(validValues)) {
    const prev = lastSeen[tag];
    if (!prev || ts >= prev.ts) {
        lastSeen[tag] = { value: value, ts: ts };
    }
}
flow.set('lastSeen', lastSeen, 'file');

// Fan-out to TB gateway (event-driven)
const DEVICE_PROFILE = flow.get('DEVICE_PROFILE') || 'sensor_planta';
const seen = flow.get('connectedDevices') || {};
const gatewayMsgs = [];
for (const tagName of Object.keys(validValues)) {
    if (!seen[tagName]) {
        gatewayMsgs.push({
            payload: JSON.stringify({ device: tagName, type: DEVICE_PROFILE }),
            topic: 'v1/gateway/connect',
            qos: 1
        });
        seen[tagName] = true;
    }
}
const gatewayPayload = {};
for (const [tag, value] of Object.entries(validValues)) {
    gatewayPayload[tag] = [{ ts: ts, values: { value: value } }];
}
gatewayMsgs.push({
    payload: JSON.stringify(gatewayPayload),
    topic: 'v1/gateway/telemetry',
    qos: 1
});
flow.set('connectedDevices', seen);

// HTTP response
msg.statusCode = 200;
msg.payload = { status: 'ok', tags: Object.keys(validValues).length };
return [gatewayMsgs, msg];

// Periodic timer-driven emit to AI. Inject fires at 1s heartbeat; we emit
// at most once every inference_emit_interval_ms (default 60000).

const fs = global.get('fs');
const runtimeConfigPath = env.get('NR_RUNTIME_CONFIG_PATH') || '/data/runtime_config.json';

// Reload runtime config if changed on disk (same cache fn_main uses).
function loadRuntimeConfig() {
    const cached = flow.get('runtimeConfigCache') || { raw: null, config: {} };
    if (!fs) return cached.config || {};
    try {
        const raw = fs.readFileSync(runtimeConfigPath, 'utf8');
        if (raw === cached.raw) return cached.config || {};
        let parsed;
        try {
            parsed = JSON.parse(raw);
        } catch (err) {
            node.warn('runtime_config parse error: ' + err.message);
            return cached.config || {};
        }
        const cfg = {};
        if (Array.isArray(parsed.expected_tags)) cfg.expected_tags = parsed.expected_tags.filter(t => typeof t === 'string');
        if (typeof parsed.ai_inference_url === 'string' && parsed.ai_inference_url.trim().length > 0) cfg.ai_inference_url = parsed.ai_inference_url.trim();
        if (typeof parsed.inference_emit_interval_ms === 'number' && parsed.inference_emit_interval_ms > 0) cfg.inference_emit_interval_ms = parsed.inference_emit_interval_ms;
        if (typeof parsed.max_tag_staleness_ms === 'number' && parsed.max_tag_staleness_ms > 0) cfg.max_tag_staleness_ms = parsed.max_tag_staleness_ms;
        if (typeof parsed.warmup_timeout_ms === 'number' && parsed.warmup_timeout_ms > 0) cfg.warmup_timeout_ms = parsed.warmup_timeout_ms;
        flow.set('runtimeConfigCache', { raw: raw, config: cfg });
        // Propagate tag-set reset across function nodes too, but only when
        // sig actually changed (undefined on first-load-after-restart → skip).
        const prevSig = flow.get('prevExpectedTagsSig');
        const newSig = (cfg.expected_tags || []).slice().sort().join(',');
        if (prevSig !== undefined && prevSig !== newSig) {
            flow.set('lastSeen', {}, 'file');
            flow.set('warmupTimeoutWarned', false);
        }
        flow.set('prevExpectedTagsSig', newSig);
        return cfg;
    } catch (_err) {
        if (cached.raw !== null) {
            flow.set('runtimeConfigCache', { raw: null, config: {} });
        }
        return {};
    }
}

const cfg = loadRuntimeConfig();
const EMIT_INTERVAL = cfg.inference_emit_interval_ms || 60000;
const TTL = cfg.max_tag_staleness_ms || 120000;
const WARMUP_TIMEOUT = cfg.warmup_timeout_ms || 600000;
const expectedTags = cfg.expected_tags;
const aiUrl = cfg.ai_inference_url;

// Process start reference for warmup timeout
let startTs = flow.get('emitProcessStartTs');
if (!startTs) {
    startTs = Date.now();
    flow.set('emitProcessStartTs', startTs);
}

const now = Date.now();
const lastEmitAttempt = flow.get('lastEmitAttemptTs') || 0;
if (now - lastEmitAttempt < EMIT_INTERVAL) {
    return null;
}
flow.set('lastEmitAttemptTs', now);

let counters = flow.get('emitCounters') || {
    emitted: 0, skippedStale: 0, skippedWarmup: 0, skippedNoConfig: 0, lastEmitTs: 0
};

if (!Array.isArray(expectedTags) || expectedTags.length === 0) {
    counters.skippedNoConfig++;
    flow.set('emitCounters', counters);
    return null;
}

const lastSeen = flow.get('lastSeen', 'file') || {};
const missingTags = expectedTags.filter(t => !(t in lastSeen));
if (missingTags.length > 0) {
    counters.skippedWarmup++;
    if ((now - startTs) > WARMUP_TIMEOUT && !flow.get('warmupTimeoutWarned')) {
        node.warn('warmup_timeout exceeded: ' + missingTags.length + '/' + expectedTags.length + ' tags still missing: ' + missingTags.slice(0, 5).join(','));
        flow.set('warmupTimeoutWarned', true);
    }
    flow.set('emitCounters', counters);
    return null;
}

const staleTags = expectedTags.filter(t => (now - lastSeen[t].ts) > TTL);
if (staleTags.length > 0) {
    counters.skippedStale++;
    flow.set('emitCounters', counters);
    return null;
}

// Build snapshot. ts = most recent tag ts included in the snapshot.
const snapshot = {};
let maxTs = 0;
for (const t of expectedTags) {
    snapshot[t] = lastSeen[t].value;
    if (lastSeen[t].ts > maxTs) maxTs = lastSeen[t].ts;
}

// Audit trail to TB (inference-input device)
const INFERENCE_DEVICE = flow.get('INFERENCE_DEVICE') || 'inference-input';
const INFERENCE_PROFILE = flow.get('INFERENCE_PROFILE') || 'inference_input';
const seen = flow.get('connectedDevices') || {};
const gatewayMsgs = [];
if (!seen[INFERENCE_DEVICE]) {
    gatewayMsgs.push({
        payload: JSON.stringify({ device: INFERENCE_DEVICE, type: INFERENCE_PROFILE }),
        topic: 'v1/gateway/connect',
        qos: 1
    });
    seen[INFERENCE_DEVICE] = true;
    flow.set('connectedDevices', seen);
}
gatewayMsgs.push({
    payload: JSON.stringify({ [INFERENCE_DEVICE]: [{ ts: maxTs, values: snapshot }] }),
    topic: 'v1/gateway/telemetry',
    qos: 1
});

let aiMsg = null;
if (aiUrl) {
    aiMsg = {
        payload: { ts: maxTs, sensors: snapshot },
        url: aiUrl,
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        requestTimeout: 5000
    };
}

counters.emitted++;
counters.lastEmitTs = now;
flow.set('emitCounters', counters);

return [gatewayMsgs, aiMsg];

// GET /api/debug/stats — observability for emit counters + per-tag staleness
const counters = flow.get('emitCounters') || {
    emitted: 0, skippedStale: 0, skippedWarmup: 0, skippedNoConfig: 0, lastEmitTs: 0
};
const lastSeen = flow.get('lastSeen', 'file') || {};
const startTs = flow.get('emitProcessStartTs') || Date.now();
const now = Date.now();

const staleness = {};
for (const tag of Object.keys(lastSeen)) {
    staleness[tag] = now - lastSeen[tag].ts;
}

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    emitCounters: counters,
    lastSeenStaleness: staleness,
    uptime_ms: now - startTs
};
return msg;
